  technical.forEach(f => { cardsHtml += `<p style="font-size:14px; line-height:1.7; margin:12px 0; color:#bbb; display:flex; align-items:flex-start;"><span style="color:${theme.accent}; font-size:14px; margin-left:10px; margin-top:2px;">⟡</span> ${f}</p>`; });
  notIncl.forEach(f => { cardsHtml += `<p style="font-size:14px; line-height:1.7; margin:12px 0; color:${theme.muted}; display:flex; align-items:flex-start;"><span style="color:${theme.muted}; font-size:12px; margin-left:10px; margin-top:4px;">✕</span> <span style="text-decoration:line-through;">${f}</span></p>`; });

  cardsHtml += '</div>';
